import React, { useState } from 'react';
import { TextField, Button, Container, Typography, Box, useMediaQuery } from '@mui/material';
import Layout from '../components/Layout';
import { useTheme } from '@mui/material/styles';
import { getCookie } from '../utils/utils';
import VerificationInput from "react-verification-input";
import '../styles/verificar-codigo.css';
import api from '../components/api';
import { navigate } from 'gatsby';

const SmsConfirmationScreen: React.FC = () => {
    const theme = useTheme();
    const email = getCookie('email');
    const [code, setCode] = useState<string>("");

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (code.length !== 6) {
            alert('Código deve possuir 6 dígitos');
        } else {
            api.post("/v1/user/check-login-code", {
                code: code,
            })
                .then((res) => {
                    navigate('/minha-conta');
                }).catch((e) => {
                    const status = e?.response?.status;
                    if (status === 429) {
                        alert('Foram realizadas muitas tentativas, solicite um novo código.');
                    } else if (status === 410 || status === 401) {
                        alert('Código expirado, solicite um novo.');
                    } else if (status === 400) {
                        alert('Código inválido.');
                    } else {
                        alert('Ocorreu um erro, tente mais tarde');
                        console.log(e);
                    }
                });
        }
    };

    const handleCodeChange = (newCode: string) => {
        setCode(newCode.toUpperCase());
    };

    return (
        <Layout>
            <Container maxWidth="sm">
                <Box mt={5} mb={8}>
                    <Typography variant="h4" align="center" gutterBottom>
                        Confirmação de E-mail
                    </Typography>
                    <Typography variant="subtitle2" align="center" gutterBottom>
                        {`Um e-mail foi enviado para ${email} contendo o código`}
                    </Typography>
                    <form onSubmit={handleSubmit}>
                        <Box mt={2} style={{ display: 'flex', justifyContent: 'center' }}>
                            <VerificationInput
                                value={code}
                                onChange={handleCodeChange}
                                autoFocus={true}
                                placeholder='-'
                                length={6}
                                inputProps={{
                                    autoComplete: 'one-time-code',
                                  }}
                                classNames={{
                                    character: "verificationchar",
                                }}
                            />
                        </Box>
                        <Box mt={4}>
                            <Button type="submit" size="large" variant="contained" color="primary" fullWidth>
                                Verificar código
                            </Button>
                        </Box>
                    </form>
                </Box>
            </Container>
        </Layout>
    );
};

export default SmsConfirmationScreen;